import React , {useContext } from 'react'
import {AppContext} from '../context/AppContext'
import Spinner from './Spinner'
import Card from './Card'

const Blogs = () => {

    //CONSUMING
    const { loading , posts} = useContext(AppContext);



  return (
    <div>
        {
            
        loading ? 
        (<Spinner></Spinner>) : 
        (
          posts.length === 0 ? 
          (<div>
            <p> No Post FOund </p>
          </div>) : 
          (posts.map( (post)=> (

            <div>
                <p>{post.title}</p>
                
            </div>

          ) ) ) 
        )


        }
    </div>
  )
}

export default Blogs
